using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int t,n;
bool check(int x)
{
    string s=to_string(x);
    string r=s;
    reverse(r.begin(),r.end());
    return s==r;
}
signed main(void)
{
    t=read();
    wh(t--)
    {
        n=read();
        bool flag=false;
        FOR(i,0,64)
        {
            if(check(n-(1ll<<i)))
            {
                flag=true;
                break;
            }
        }
        if(flag)Yes
        else No
    }
    return false;
}
